import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { toast } from "react-toastify";

function Reports() {
  const user = useSelector((state) => state.auth.user);
  const [reports, setReports] = useState([]);
  const [courses, setCourses] = useState([]);
  const [reportType, setReportType] = useState("");

  useEffect(() => {
    fetch("http://localhost:3001/reports")
      .then((res) => res.json())
      .then((data) => {
        // Ensure data is an array
        setReports(Array.isArray(data) ? data : []);
      })
      .catch((error) => {
        toast.error("Ошибка загрузки отчетов");
        setReports([]);
      });
    fetch("http://localhost:3001/courses")
      .then((res) => res.json())
      .then((data) => setCourses(Array.isArray(data) ? data : []))
      .catch((error) => toast.error("Ошибка загрузки курсов"));
  }, []);

  async function handleGenerateReport(e) {
    e.preventDefault();
    if (!reportType) {
      toast.error("Выберите тип отчета!");
      return;
    }

    try {
      let reportData = {};
      if (reportType === "enrollment") {
        const enrollmentsResponse = await fetch("http://localhost:3001/enrollments");
        const enrollments = await enrollmentsResponse.json();
        reportData = courses.reduce((acc, course) => {
          const count = enrollments.filter((e) => e.courseId === course.id).length;
          acc[course.name] = count;
          return acc;
        }, {});
      } else if (reportType === "review") {
        const reviewsResponse = await fetch("http://localhost:3001/reviews");
        const reviews = await reviewsResponse.json();
        reportData = courses.reduce((acc, course) => {
          const courseReviews = reviews.filter((r) => r.courseId === course.id);
          const avgRating =
            courseReviews.length > 0
              ? (
                  courseReviews.reduce((sum, r) => sum + r.rating, 0) / courseReviews.length
                ).toFixed(2)
              : "Нет отзывов";
          acc[course.name] = avgRating;
          return acc;
        }, {});
      }

      const newReport = {
        type: reportType,
        data: reportData,
        createdAt: new Date().toISOString(),
      };

      const response = await fetch("http://localhost:3001/reports", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newReport),
      });

      if (response.ok) {
        const createdReport = await response.json();
        setReports([...reports, createdReport]);
        setReportType("");
        toast.success("Отчет успешно сгенерирован!");
        await fetch("http://localhost:3001/notifications", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            userId: user.id,
            message: `Сгенерирован отчет типа "${reportType === "enrollment" ? "Записи" : "Отзывы"}".`,
            createdAt: new Date().toISOString(),
          }),
        });
      } else {
        toast.error("Не удалось сгенерировать отчет");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при генерации отчета");
    }
  }

  if (user?.role !== "admin") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Отчеты</h1>
      <div className="row">
        <div className="col-md-6">
          <div className="card shadow mb-4">
            <div className="card-body">
              <h2 className="card-title">Сгенерировать отчет</h2>
              <form onSubmit={handleGenerateReport}>
                <div className="mb-3">
                  <label htmlFor="reportType" className="form-label">Тип отчета</label>
                  <select
                    id="reportType"
                    className="form-select"
                    value={reportType}
                    onChange={(e) => setReportType(e.target.value)}
                    required
                  >
                    <option value="">-- Выберите тип отчета --</option>
                    <option value="enrollment">Количество записей на курсы</option>
                    <option value="review">Средняя оценка курсов</option>
                  </select>
                </div>
                <button type="submit" className="btn btn-primary w-100">Сгенерировать</button>
              </form>
            </div>
          </div>
        </div>
        <div className="col-md-6">
          <div className="card shadow">
            <div className="card-body">
              <h2 className="card-title">Список отчетов</h2>
              {reports.length === 0 ? (
                <p>Отчетов нет</p>
              ) : (
                <ul className="list-group">
                  {reports.map((report) => (
                    <li key={report.id} className="list-group-item">
                      <strong>Тип:</strong> {report.type === "enrollment" ? "Записи" : "Отзывы"}<br />
                      <strong>Дата:</strong> {new Date(report.createdAt).toLocaleString()}<br />
                      <strong>Данные:</strong>
                      <ul>
                        {Object.entries(report.data).map(([key, value]) => (
                          <li key={key}>
                            {key}: {value}
                          </li>
                        ))}
                      </ul>
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Reports;
